INSERT INTO 
    bonus_details (bonus_id, condition_text, explanatory_text, flavor_note, tier_explanation) 
VALUES
    (1, 'Birds with body parts in their names', 'Body parts include beak, belly, bill, breast, cap, chin, collar, crest, crown, eye, face, head, neck, rump, shoulder, tail, throat, wing', 'Include these terms, if you play with:<br>European expansion: back, leg, toe<br>Oceania expansion: back, ear, foot, head, mouth, wattle<br>Asia: brow, nape, vent, wattle<br><ul><li>The Azure Tit, Willow Tit, and White-Browed Tit-Warbler do not qualify for the Anatomist card: in this case, "tit" comes from an Old English word meaning "small thing."</li></ul><br>Americas expansion: brow, ear, foot, head, leg, nape, tuft, wattle', 'Has a lower barrier to entry and a good payoff on the top end. Pairs well with Photographer.'),
    (2, 'Birds worth less than 4 points', NULL, 'Count the birds you played that have a face value of 0, 1, 2, or 3 points.', 'Another bonus card that requires you to amass low point value birds, specifically so. You''re going to need a strong engine to climb out of a strategy that creates a bird point deficit like this.'),
    (3, 'Birds with a [flocking] power', NULL, 'Count the birds you played that have the specific symbol shown on this bonus card. The symbol should be on the left-hand side of the bird''s brown power.', 'Tucking engines want this card because it adds two points to every flocking bird. It''s a no-brainer pick when you''re amassing flocking birds. Generally speaking, these birds tend to be lower point value so they need all the help they can get.'),
    (4, 'Birds that eat [seed]', NULL, NULL, 'Birds that eat seeds are fairly common but a lot of them are worth smaller point values. This bonus card has a high ceiling at both the low end (five birds) and the top end (eight birds), so to score more points on Bird Feeder, you have to amass a lot of birds that are probably worth fewer points. The higher ceilings on this card are likely a balancing factor for the higher volume of seed eating birds in the game.'),
    (5, 'Birds that have at least 4 eggs laid on them', NULL, 'Count only bird cards that have 4 egg tokens sitting on them at game end.', 'You probably aren''t going to score a lot of points off this card. One to three seems realistic. You have to first play a qualifying bird (28% isn''t bad) but then you have to lay four eggs on it, which requires extra actions. This card definitely favors egg spam.'),
    (6, 'Birds with geography terms in their name', 'Terms include American, Atlantic, Baltimore, California, Canada, Carolina, Chihuahua, Eastern, Inca, Mississippi, Mountain, Northern, Prairie, Sandhill, Savannah, Western', 'Include these terms, if you play with:<br>European expansion: Corsican, Eurasian, European, Moor<br>Oceania expansion: Australasian, Australian, mallee, New Holland, North, Pacific, plains, sea, scrub, South<br>Asia: East, forest, Himalaya, India, jungle, marsh, Orient, Philippine, Sri Lanka, West<br>Americas expansion: Altamira, Amazon, Andes, Antioquia, Brazil, Chiloé, Grassland, Jamaica, Marsh, Meadow, Neotropic, Oasis, Orinoco, Peru, Savanna, Sierra, South, Titicaca, Tropic', 'Has a lower barrier to entry and a good payoff on the top end.'),
    (7, 'Birds in your habitat with the fewest birds.', 'Ties count.', 'Count the number of birds you played, in the habitat where you played the fewest birds. If you have two habitats tied for fewest birds, you may still score this bonus. For example, if all of your habitats have 3 birds in them, your habitat with the fewest birds has 3 birds in it.', 'This should probably score you four points every time. With some focus, you should be able to pull down six points.'),
    (8, 'Birds with [ground] nests', 'Birds must have a [ground] or [star] nest symbol.', 'Count the number of birds you played that have the specific nest symbol shown on the card. Star nests [star] are wild. Birds with star nests count toward all four of these bonuses.', '20% of seven to nine point birds have ground nests; plus 11.4% more with star nests.'),
    (9, 'Birds with a [predator] power', NULL, 'Count the birds you played that have the specific symbol shown on this bonus card. The symbol should be on the left-hand side of the bird''s brown power.', 'There are a lot of cheap birds that have the predator tag, making them highly food efficient points with Falconer. Big point predators become even bigger point bombs with this card. Pairs incredibly well with several bonus cards, especially Rodentologist.'),
    (10, 'Birds that eat [fish]', NULL, NULL, 'Has a lower barrier to entry and a good payoff on the top end.'),
    (11, 'Birds that eat only [invertebrate]', NULL, NULL, 'Adds two points per qualifying bird but there aren''t many that qualify. Birds must only eat invertebrates.'),
    (12, 'Birds that can only live in [forest]', NULL, 'Count the number of birds you played that only have the habitat symbol shown on this bonus card. If a bird has the option to live in more than one type of habitat, it cannot count toward this bonus.', 'Like Wetlands Scientist, scoring with Forester tends to be accidental for me but we''ve all had those games where we stumble into a lot of cheap food caching birds such as Mountain Chickadee, Carolina Chickadee, and Juniper Titmouse.'),
    (13, 'Birds named after a person', 'Any bird with an ''s in its name.', NULL, 'Adds two points per qualifying bird but there aren''t many that qualify.'),
    (14, 'Birds with wingspans over 65 cm', NULL, 'Count the birds you played that have wingspans over 65cm. Wingspans of exactly 65cm do not count toward this bonus.', 'A lot of big point birds have wingspans over 65CM. This card pairs especially well with Falconer, Rodentologist, and/or Platform Builder.'),
    (15, 'Birds with [cavity] nests', 'Birds must have a [cavity] or [star] nest symbol.', 'Count the number of birds you played that have the specific nest symbol shown on the card. Star nests [star] are wild. Birds with star nests count toward all four of these bonuses.', '8.5% of seven to nine point birds have cavity nests; plus 11.4% more with star nests.'),
    (16, 'Birds that eat [wild]', 'Any bird that specifically has a [wild] symbol as part of its food cost.', NULL, 'There are many cheap and effective birds that cost a single wild food, making them highly food efficient points with Omnivore Specialist. Core Set Hummingbirds and Crows are some examples of these birds. 75% of the Power 4 (Chihuahuan Raven, Common Raven, and Franklin''s Gull) pick up two more points from this card. There are other choice cards that qualify such as Whooping Crane, Wood Stork, Australian Raven, Black Swan and Mute Swan.'),
    (17, 'Birds that have at least 1 egg laid on them', NULL, 'Count only bird cards that have at least 1 egg token sitting on them at game end.', 'Nine birds shouldn''t be too hard to get on the board and once they are there, it''s not too difficult to get one egg on each. Time has proven that this is one of the easiest bonus cards to score and it reinforces egg spam strategies which remain one of the best overall strategies.'),
    (18, 'Birds with wingspans 30 cm or less', NULL, 'Count the birds you played that have wingspans 30cm or less. Wingspans of exactly 30cm count toward this bonus.', 'Birds with wingspans of 30CM or less are generally worth fewer points. Bonus cards that require you to amass low point value birds are less desirable.'),
    (19, 'Birds with colors in their names', 'Colors include ash, black, blue, bronze, brown, cerulean, chestnut, ferruginous, gold, gray, green, indigo, lazuli, purple, red, rose, roseate, ruby, ruddy, rufous, snowy, violet, white, yellow', 'Include these terms, if you play with:<br>European expansion: coal, grey<br>Oceania expansion: crimson, orange, pink, rufous, silver, sulphur, tawny<br>Asia: azure, emerald, fire, olive, plumbeous, teal, verditer, violet<br><br>The European Expansion rulebook erroneously includes honey as a term for the Photographer bonus.<br>card. Honey does not count as a color word.<br><br><ul><li>Coppersmith Barbet dose not qualify for the Photographer card.</li></ul><br>Americas expansion: amethyst, banana, cinnamon, clay-colored, crimson, fire, gilded, hyacinth, orange, rufescent, scarlet, teal, topaz, turquoise, ultramarine, vermilion', 'Pairs well with Anatomist.'),
    (20, 'Birds with [platform] nests', 'Birds must have a [platform] or [star] nest symbol.', 'Count the number of birds you played that have the specific nest symbol shown on the card. Star nests [star] are wild. Birds with star nests count toward all four of these bonuses.', 'A lot of big point, rodent-eating predators have platform nests (48.5% of seven to nine point birds have platform nests; plus 11.4% more with star nests). This card pairs especially well with Falconer, Rodentologist, and/or Large Bird Specialist. Here''s another card where 75% of the Power 4 qualify.'),
    (21, 'Birds that can only live in [grassland]', NULL, 'Count the number of birds you played that only have the habitat symbol shown on this bonus card. If a bird has the option to live in more than one type of habitat, it cannot count toward this bonus.', 'Has a lower barrier to entry and a good payoff on the top end.'),
    (22, 'Birds that eat [rodent]', NULL, NULL, 'There are a lot of cheap birds that have a single rat in their food cost, making them highly food efficient points with Rodentologist. Big point rodent-eating birds become even bigger point bombs with this card. Pairs incredibly well with several bonus cards, especially Falconer. Chihuahuan Raven and Common Raven qualify too (50% of the Power 4).'),
    (23, 'Bird cards in hand at end of game', NULL, 'Count the bird cards still in your hand at the end of the game.', 'Amassing cards in hand is not usually a viable strategy. Certain tucking engines will have a large volume of cards in hand but more often than not, this card is counter-intuitive pick. You want to play birds, not hoard them.'),
    (24, 'Birds that eat [fruit]', NULL, NULL, NULL),
    (25, 'Birds that can only live in [wetland]', NULL, 'Count the number of birds you played that only have the habitat symbol shown on this bonus card. If a bird has the option to live in more than one type of habitat, it cannot count toward this bonus.', NULL),
    (26, 'Birds with [bowl] nests', 'Birds must have a [bowl] or [star] nest symbol.', 'Count the number of birds you played that have the specific nest symbol shown on the card. Star nests [star] are wild. Birds with star nests count toward all four of these bonuses.', '11.4% of seven to nine point birds have cup nests; plus 11.4% more with star nests.');